import pexpect
import sys

b64 = ""
cmd = f"rm -rf /tmp/k8s_deploy && mkdir -p /tmp/k8s_deploy && echo '{b64}' | base64 -d > /tmp/k8s_deploy/k8s.tar.gz && cd /tmp/k8s_deploy && tar -xzf k8s.tar.gz && rm k8s.tar.gz && echo '2001Bedir..' | sudo -S kubectl apply -f ."

child = pexpect.spawn(f"ssh -o StrictHostKeyChecking=no bedir@ssh.lumoraboutique.com \"{cmd}\"")
child.expect(['[Pp]assword:', pexpect.EOF, pexpect.TIMEOUT], timeout=15)
if child.after == pexpect.EOF or child.after == pexpect.TIMEOUT:
    print("Failed to get password prompt")
    sys.exit(1)

child.sendline("2001Bedir..")
child.expect(pexpect.EOF, timeout=120)
print(child.before.decode('utf-8'))
